import { HttpClient } from "@angular/common/http";
import {
  Component,
  Inject,
  EventEmitter,
  Input,
  OnInit,
  Output,
  ViewChild,
  OnChanges,
  SimpleChanges,
} from "@angular/core";
import { DatePipe } from "@angular/common";
import { format, getMonth, parse } from "date-fns";
import { Capacitor } from "@capacitor/core";
import { DOCUMENT } from "@angular/common";
import { AlertController, ModalController } from "@ionic/angular";
import { FormBuilder, FormControl, Validators } from "@angular/forms";
import { EnvService } from "src/app/core/services/env.service";
import { User } from "../../../Models/Permissions/User";
import { Permission } from "../../../Models/Permissions/Permission";
import { OverlayEventDetail } from "@ionic/core/components";
import { TranslateService } from "@ngx-translate/core";
import {
  UserBranch,
  BranchReference,
} from "src/app/views/Models/Settings/BranchReference";
import { Console, error } from "console";
import { AlertService } from "src/app/core/services/alert.service";
import { OfficerService } from "src/app/core/services/officer.service";
import { officerResponseModal as Officer } from "src/app/views/Models/Officer/Officer";
import { BranchService } from "src/app/core/services/branch.service";
import { Item } from "../../../Models/Types/item.model";

@Component({
  selector: "app-add-branchs-for-user",
  templateUrl: "./add-branchs-for-user.page.html",
  styleUrls: ["./add-branchs-for-user.page.scss"],
})
export class AddBranchsForUserPage implements OnInit {
  showLoader: boolean = false;
  initialLoad: boolean = true;

  days: string[][];
  permissions: Permission[] = [];
  branchReferences: BranchReference[] = [];
  selectedUser: User;
  branches: UserBranch[] = [];
  allOfficers: Officer[];
  branchOfficers: { [branch: string]: Item[] } = {};

  selectedPermission: BranchReference[];
  selectedAllPermissions: boolean;
  constructor(
    private env: EnvService,
    private http: HttpClient,
    public translate: TranslateService,
    private alertService: AlertService,
    private officerService: OfficerService,
    private branchService: BranchService
  ) {}

  async ngOnInit() {
    await this.GetAllOfficers();
  }

  ngOnDestroy(): void {}

  async GetAllOfficers() {
    this.showLoader = true;
    await this.officerService
      .getAllOfficers()
      .toPromise()
      .then((result) => {
        this.allOfficers = result;
        this.showLoader = false;
      })
      .catch((error) => {
        console.log(error);
        this.showLoader = false;
      });
  }

  userSelected(user: User): void {
    this.selectedUser = user;
    this.showLoader = true;
    this.branchService
      .getAllBranchesWithUserAccess(user.user_name)
      .then((data) => {
        this.branches = data;
        console.log("User Branches", this.branches);
        this.branches.forEach((branch) => {
          let branchOfficers = this.allOfficers
            .filter((officer) => {
              return officer.branch_code == branch.branch_code;
            })
            .map<Item>((officer) => {
              return {
                value: officer.officer_key.toString(),
                text: officer.officer_name,
              };
            });
          console.log(branchOfficers, branchOfficers.length > 0);
          if (branchOfficers.length > 0)
            branchOfficers = [
              { value: null, text: "لا يوجد اختيار" },
              ...branchOfficers,
            ];
          this.branchOfficers[branch.branch_code] = branchOfficers;
        });
        this.showLoader = false;
      })
      .catch((err) => {
        console.log(err);
        this.showLoader = false;
      });
  }
  DeselectUser() {
    this.selectedUser = null;
    console.log(this.branches);
  }
  async ChangePermissions(value: number) {
    this.showLoader = true;
    var alertText = value == 1 ? "منح" : "إلغاء";
    if (
      !(await this.alertService.SaveAlert(
        `هل تريد ${alertText} جميع الصلاحيات؟`
      ))
    ) {
      this.showLoader = false;
      return;
    }
    if (value === 1) {
      this.branchService
        .addAllBranchesToUser(this.branches)
        .then(() => {
          this.userSelected(this.selectedUser);
          this.showLoader = false;
        })
        .catch((error) => {
          console.log(error.message);
          this.showLoader = false;
        });
    } else {
      this.branchService
        .removeAllBranchesFromUser(this.selectedUser.user_name)
        .then(() => {
          this.userSelected(this.selectedUser);
          this.showLoader = false;
        })
        .catch((error) => {
          this.alertService.showAlertError(error.error, false);
          this.userSelected(this.selectedUser);
          console.log(error);
          this.showLoader = false;
        });
    }
  }
  ChangePermission(userBranch: UserBranch, value: number): void {
    this.showLoader = true;

    if (value === 1) {
      this.branchService
        .addBranchToUser(
          this.selectedUser.user_name,
          userBranch.branch_code.toString(),
          userBranch.officer_key
        )
        .then(() => {
          this.userSelected(this.selectedUser);
          this.showLoader = false;
        })
        .catch((error) => {
          console.log(error);
          this.alertService.showAlertError(error.error, false);
          this.showLoader = false;
        });
    } else {
      this.branchService
        .removeBranchFromUser(
          this.selectedUser.user_name,
          userBranch.branch_code.toString()
        )
        .then(() => {
          this.userSelected(this.selectedUser);
          this.showLoader = false;
        })
        .catch((error) => {
          this.alertService.showAlertError(error.error, false);
          console.log(error);
          this.showLoader = false;
        });
    }
  }

  checkAllBranchEnable(BranchForUsers: UserBranch[]): boolean {
    return BranchForUsers.every((item) => item.permission == 1);
  }
  checkAllBranchDisable(BranchForUsers: UserBranch[]): boolean {
    return BranchForUsers.every((item) => item.permission == 0);
  }
}
